#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int MAXN=1e6+5;
ll n,ans=INT_MIN,f[MAXN]={0};
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%lld",&n);
	for(int i=1;i<=n;++i){
		scanf("%lld",f+i);
		f[i]=max(f[i-1]+f[i],f[i]);
		ans=max(f[i],ans);
	}printf("%lld",ans);
    return false;
}
